"""Auto-load Streamlit defaults from <venv>/.streamlit/config.toml.

Activated on Python startup via streamlit-env.pth.  Reads the TOML config
that Ambari manages at ``<venv>/.streamlit/config.toml`` and exports each
setting as a ``STREAMLIT_<SECTION>_<KEY>`` environment variable.

Already-set env vars are never overwritten, so users can still override
individual settings per invocation.
"""

import os
import sys


def _apply():
    config_path = os.path.join(sys.prefix, "conf", "streamlit", "config.toml")
    if not os.path.isfile(config_path):
        return

    try:
        import tomllib
    except ModuleNotFoundError:
        return

    try:
        with open(config_path, "rb") as f:
            config = tomllib.load(f)
    except Exception:
        return

    for section, values in config.items():
        if not isinstance(values, dict):
            continue
        for key, value in values.items():
            env_key = f"STREAMLIT_{section}_{key}".upper()
            if env_key not in os.environ:
                os.environ[env_key] = str(value).lower() if isinstance(value, bool) else str(value)


_apply()
